/**
 * Unit tests for spawn-intent-logger PreToolUse[Task] hook
 *
 * The SubagentStart payload carries no description/prompt (live-captured on
 * CC 2.1.173), so spawn descriptions must be logged at PreToolUse where the
 * Agent tool's args are available. These tests lock that contract.
 */

import { describe, test, expect, vi, beforeEach } from 'vitest';
import type { HookInput } from '../../types.js';

const { mockBufferWrite } = vi.hoisted(() => ({
  mockBufferWrite: vi.fn(),
}));

vi.mock('../../lib/analytics-buffer.js', () => ({
  bufferWrite: mockBufferWrite,
  flush: vi.fn(),
  pendingCount: vi.fn(() => 0),
  _resetForTesting: vi.fn(),
}));

import {
  spawnIntentLogger,
  deriveSpawnDescription,
  SPAWN_DESCRIPTION_MAX,
} from '../../pretool/task/spawn-intent-logger.js';

function makeInput(toolInput: Record<string, unknown>, overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Task',
    session_id: 'session-spawn-intent',
    tool_input: toolInput,
    ...overrides,
  };
}

function loggedEntry(): Record<string, unknown> {
  const call = mockBufferWrite.mock.calls.find(
    (c: unknown[]) => typeof c[0] === 'string' && c[0].includes('subagent-spawns.jsonl'),
  );
  expect(call).toBeDefined();
  return JSON.parse((call![1] as string).trim());
}

beforeEach(() => {
  mockBufferWrite.mockClear();
});

describe('deriveSpawnDescription', () => {
  test('explicit description wins over prompt', () => {
    const desc = deriveSpawnDescription(
      makeInput({ description: 'Explicit summary', prompt: 'Long prompt body' }),
    );
    expect(desc).toBe('Explicit summary');
  });

  test('task_description accepted (context-stager parity)', () => {
    const desc = deriveSpawnDescription(
      makeInput({ description: '', task_description: 'From task_description', prompt: 'x' }),
    );
    expect(desc).toBe('From task_description');
  });

  test('falls back to first non-empty prompt line', () => {
    const desc = deriveSpawnDescription(
      makeInput({ description: '', prompt: '\n\n  Investigate flaky CI failures.  \nThen report.' }),
    );
    expect(desc).toBe('Investigate flaky CI failures.');
  });

  test('truncates to SPAWN_DESCRIPTION_MAX chars', () => {
    const desc = deriveSpawnDescription(makeInput({ description: 'y'.repeat(500) }));
    expect(desc.length).toBe(SPAWN_DESCRIPTION_MAX);
  });

  test('empty when neither description nor prompt present', () => {
    expect(deriveSpawnDescription(makeInput({}))).toBe('');
  });
});

describe('spawnIntentLogger', () => {
  test('appends pretool-tagged entry with type + description + tool_use_id', () => {
    const result = spawnIntentLogger(
      makeInput(
        { subagent_type: 'general-purpose', description: 'Research the auth flow' },
        { tool_use_id: 'toolu_123' },
      ),
    );

    expect(result.continue).toBe(true);
    const entry = loggedEntry();
    expect(entry.source).toBe('pretool');
    expect(entry.subagent_type).toBe('general-purpose');
    expect(entry.description).toBe('Research the auth flow');
    expect(entry.tool_use_id).toBe('toolu_123');
    expect(entry.session_id).toBe('session-spawn-intent');
    expect(entry).toHaveProperty('timestamp');
  });

  test('silent no-op without subagent_type (non-Agent Task shapes)', () => {
    const result = spawnIntentLogger(makeInput({ description: 'no type' }));

    expect(result.continue).toBe(true);
    expect(mockBufferWrite).not.toHaveBeenCalled();
  });

  test('never throws when the write fails', () => {
    mockBufferWrite.mockImplementationOnce(() => {
      throw new Error('disk full');
    });

    expect(() =>
      spawnIntentLogger(makeInput({ subagent_type: 'Explore', description: 'x' })),
    ).not.toThrow();
  });
});
